esqlQuery.esql:
FROM logs-*
// Restrict to Azure Activity Logs (Security category)
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "Security"
// Derive actor for grouping (enduser.id or user.name)
| EVAL actor = COALESCE(enduser.id, user.name, "unknown")
// Optional: add azure.security.severity IN ("High", "Critical") to focus on elevated severity only
| STATS event_count = COUNT(*), severities = VALUES(azure.security.severity), actions = VALUES(azure.security.action_taken) BY actor, azure.security.domain_name, process.executable.path
| SORT event_count DESC
| LIMIT 20
